{"content": """"博查AI搜索 (Bocha) — plugin form.

Subclasses :class:`agent.web_search_provider.WebSearchProvider`.
Search-only provider (web_search capability).

Config keys this provider responds to::

    web:
      search_backend: "bocha"     # explicit per-capability
      backend: "bocha"            # shared fallback

Auth env var::

    BOCHA_API_KEY=...    # https://open.bochaai.com/dashboard

API reference:
    POST https://api.bochaai.com/v1/web-search
    Authorization: Bearer <key>
    Body: {"query": "...", "count": N, "freshness": "noLimit"}
"""

from __future__ import annotations

import logging
import os
from typing import Any, Dict

from agent.web_search_provider import WebSearchProvider

logger = logging.getLogger(__name__)

_BOCHA_ENDPOINT = "https://api.bochaai.com/v1/web-search"


class BochaWebSearchProvider(WebSearchProvider):
    """Search-only provider for 博查AI搜索 (Bocha).

    Bocha is a Chinese-native web search API designed for AI agents and RAG.
    It indexes ~10B Chinese web pages including news, images, videos,
    encyclopedia entries, and academic content.

    Features:
    - Natural language search with semantic re-ranking
    - Freshness filter (noLimit / pastDay / pastWeek / pastMonth)
    - Answer summarization (optional)
    """

    @property
    def name(self) -> str:
        return "bocha"

    @property
    def display_name(self) -> str:
        return "博查AI搜索 (Bocha)"

    def is_available(self) -> bool:
        """Return True when ``BOCHA_API_KEY`` is set."""
        return bool(os.getenv("BOCHA_API_KEY", "").strip())

    def supports_search(self) -> bool:
        return True

    def supports_extract(self) -> bool:
        return False

    def supports_crawl(self) -> bool:
        return False

    def search(self, query: str, limit: int = 5) -> Dict[str, Any]:
        """Execute a search against the Bocha Web Search API.

        Returns ``{"success": True, "data": {"web": [...]}}`` on success,
        or ``{"success": False, "error": str}`` on failure.
        """
        import httpx

        api_key = os.getenv("BOCHA_API_KEY", "").strip()
        if not api_key:
            return {"success": False, "error": "BOCHA_API_KEY is not set"}

        # Bocha's `count` is capped at 20.
        count = max(1, min(int(limit), 20))

        payload = {
            "query": query,
            "freshness": "noLimit",
            "count": count,
            "answer": False,
        }

        try:
            resp = httpx.post(
                _BOCHA_ENDPOINT,
                json=payload,
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                },
                timeout=30,
            )
            resp.raise_for_status()
        except httpx.HTTPStatusError as exc:
            logger.warning("Bocha Search HTTP %d: %s", exc.response.status_code, exc)
            detail = ""
            try:
                body = exc.response.json()
                detail = body.get("message", str(exc))
            except Exception:
                detail = str(exc)
            return {
                "success": False,
                "error": f"Bocha Search returned HTTP {exc.response.status_code}: {detail}",
            }
        except httpx.RequestError as exc:
            logger.warning("Bocha Search request error: %s", exc)
            return {"success": False, "error": f"Could not reach Bocha Search: {exc}"}

        try:
            data = resp.json()
        except Exception:
            logger.warning("Bocha Search response parse error")
            return {"success": False, "error": "Could not parse Bocha Search response as JSON"}

        # Normalize Bocha response to standard shape
        # Bocha returns: {"code": 200, "data": {"webPages": {"value": [...]}}}
        # or older format: {"webPages": {"value": [...]}}
        web_pages = []
        try:
            wrapped = data.get("data", data)  # handle {"data": {...}} wrapper
            pages = wrapped.get("webPages", {}).get("value", [])
            if not pages and isinstance(wrapped.get("webPages"), list):
                pages = wrapped["webPages"]
            web_pages = pages
        except Exception:
            web_pages = []

        web_results = [
            {
                "title": str(r.get("name", "")),
                "url": str(r.get("url", "")),
                "description": str(r.get("snippet", "")),
                "position": i + 1,
            }
            for i, r in enumerate(web_pages[:limit])
        ]

        logger.info(
            "Bocha Search '%s': %d results (from %d raw, limit %d)",
            query,
            len(web_results),
            len(web_pages),
            limit,
        )

        return {"success": True, "data": {"web": web_results}}

    def get_setup_schema(self) -> Dict[str, Any]:
        return {
            "name": "博查AI搜索 (Bocha)",
            "badge": "cn",
            "tag": "中文世界知识搜索 — 百亿中文网页索引，免费额度。",
            "env_vars": [
                {
                    "key": "BOCHA_API_KEY",
                    "prompt": "博查 API Key",
                    "url": "https://open.bochaai.com/dashboard",
                },
            ],
        }
